-- ============================================================\n-- 006 — Ajout du champ is_admin sur profiles\n-- ============================================================\n\nALTER TABLE profiles ADD COLUMN IF NOT EXISTS is_admin BOOLEAN NOT NULL DEFAULT FALSE;\n\n-- Policy : admin peut tout faire sur spaces\nCREATE POLICY \"spaces_admin_all\"\n  ON spaces FOR ALL\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()))\n  WITH CHECK ((SELECT is_admin FROM profiles WHERE id = auth.uid()));\n\n-- Policy : admin peut tout faire sur space_photos\nCREATE POLICY \"space_photos_admin_all\"\n  ON space_photos FOR ALL\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()))\n  WITH CHECK ((SELECT is_admin FROM profiles WHERE id = auth.uid()));\n